import { useEffect, useState } from "react";
import { useParams } from "react-router-dom";

function ServiceDetail() {
  const { id } = useParams();
  const [service, setService] = useState(null);

  useEffect(() => {
    fetch(`http://localhost:8080/api/services/${id}`)
      .then((res) => res.json())
      .then((data) => setService(data))
      .catch((err) => console.log(err));
  }, [id]);

  if (!service) return <p style={{ textAlign: "center" }}>Loading...</p>;

  return (
    <div
      style={{
        display: "flex",
        gap: "40px",
        padding: "40px",
        maxWidth: "1100px",
        margin: "0 auto",
      }}
    >
      <div style={{ flex: 2 }}>
        <img
          src={
            service.imageUrl ||
            "https://via.placeholder.com/600x300?text=No+Image"
          }
          alt={service.title}
          style={{ width: "100%", borderRadius: "10px" }}
        />

        <h1 style={{ marginTop: "20px" }}>{service.title}</h1>

        <p style={{ color: "gray" }}>
          by {service.freelancer?.email || "User"}
        </p>

        <p style={{ marginTop: "20px", lineHeight: "1.6" }}>
          {service.description}
        </p>
      </div>

      <div
        style={{
          flex: 1,
          border: "1px solid #ddd",
          borderRadius: "10px",
          padding: "20px",
          height: "fit-content",
          boxShadow: "0 0 10px rgba(0,0,0,0.05)",
        }}
      >
        <h2>{service.price} €</h2>

        <button
          onClick={() => {
            const token = localStorage.getItem("token");

            if (!token) {
              alert("Devi fare login prima");
              window.location.href = "/login";
            } else {
              alert(
                "Ordine simulato con successo! (Nessun pagamento reale è stato effettuato)",
              );
            }
          }}
          style={{
            width: "100%",
            marginTop: "20px",
            padding: "12px",
            backgroundColor: "#1dbf73",
            color: "white",
            border: "none",
            borderRadius: "5px",
            fontWeight: "bold",
            cursor: "pointer",
          }}
        >
          Continue
        </button>

        <p style={{ marginTop: "10px", fontSize: "14px", color: "gray" }}>
          No payment required yet
        </p>
      </div>
    </div>
  );
}

export default ServiceDetail;
